import React, { useState } from 'react';
import { useDroppable } from '@dnd-kit/core';

function TableDropZone({ table, guests, readOnly, onUpdate, onRemove }) {
  const { isOver, setNodeRef } = useDroppable({ id: table.id });
  const tableGuests = table.guests.map(id => guests.find(g => g.id === id)).filter(Boolean);

  return (
    <div className={`table-card ${isOver ? 'drop-hover' : ''}`}>
      <div className="table-card-header">
        {readOnly ? (
          <span>{table.name}</span>
        ) : (
          <input
            type="text"
            value={table.name}
            onChange={(e) => onUpdate(table.id, { name: e.target.value })}
          />
        )}
        <span className="seat-count">{tableGuests.length}/{table.seats}</span>
        {!readOnly && (
          <button className="remove-btn" onClick={() => onRemove(table.id)}>×</button>
        )}
      </div>
      <div ref={setNodeRef} className="table-guests">
        {tableGuests.length === 0 ? (
          <div className="empty">Drop guests here</div>
        ) : (
          tableGuests.map(guest => (
            <div key={guest.id} className="guest-item">
              <span>{guest.name}</span>
              {!readOnly && <button onClick={() => {
                const newGuests = table.guests.filter(id => id !== guest.id);
                onUpdate(table.id, { guests: newGuests });
              }}>×</button>}
            </div>
          ))
        )}
      </div>
    </div>
  );
}

function AddTableButton({ onAdd }) {
  const [seats, setSeats] = useState(10);
  const [showInput, setShowInput] = useState(false);

  if (!showInput) {
    return (
      <div className="add-table-card" onClick={() => setShowInput(true)}>
        <span>+ Add Table</span>
      </div>
    );
  }

  return (
    <div className="add-table-card" style={{ flexDirection: 'column', gap: 10 }}>
      <input
        type="number"
        value={seats}
        onChange={e => setSeats(Math.max(1, parseInt(e.target.value) || 1))}
        style={{ width: 80, padding: '6px 10px', borderRadius: 4, border: '1px solid #ddd' }}
        placeholder="Seats"
      />
      <div style={{ display: 'flex', gap: 8 }}>
        <button className="btn" onClick={() => { onAdd(seats); setShowInput(false); }}>Add</button>
        <button className="btn btn-secondary" onClick={() => setShowInput(false)}>Cancel</button>
      </div>
    </div>
  );
}

function TableFloor({ tables, guests, onAddTable, onUpdateTable, onRemoveTable, readOnly }) {
  return (
    <div className="table-floor">
      {tables.map(table => (
        <TableDropZone
          key={table.id}
          table={table}
          guests={guests}
          readOnly={readOnly}
          onUpdate={onUpdateTable}
          onRemove={onRemoveTable}
        />
      ))}
      {!readOnly && onAddTable && <AddTableButton onAdd={onAddTable} />}
      {tables.length === 0 && !readOnly && (
        <div style={{ width: '100%', textAlign: 'center', color: '#999', padding: 40 }}>
          No tables yet. Click "Add Table" to get started.
        </div>
      )}
    </div>
  );
}

export default TableFloor;
